import { describe, it, expect } from "vitest";
import { runScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums", () => {
    it.todo("empty item list yields premium of 5 G (processing fee only)");
    it.todo("single plain sword yields 100 G base + 10 G first insurance + 5 G fee = 115 G for newcomer");
    it.todo("single plain amulet yields 60 G base + 6 G first insurance + 5 G fee = 71 G for newcomer");
    it.todo("single plain staff yields 80 G base + 8 G first insurance + 5 G fee = 93 G for newcomer");
    it.todo("single plain potion yields 40 G base + 4 G first insurance + 5 G fee = 49 G for newcomer");
    it.todo("single rune yields 25 G base + 3 G first insurance (rounded up) + 5 G fee = 33 G for newcomer");
  });

  describe("quote - component building blocks", () => {
    it.todo("2 runes yields 50 G base premium (no block)");
    it.todo("3 runes yields 60 G base premium (block applies)");
    it.todo("4 runes yields 100 G base premium (no block)");
    it.todo("3 runes + 3 moonstones yields 120 G base premium (two separate blocks)");
  });

  describe("quote - item modifiers", () => {
    it.todo("cursed sword adds 50% surcharge on that item's base premium");
    it.todo("sword with enchantment 5 adds 30% high-enchantment surcharge");
    it.todo("sword with enchantment 4 does not add high-enchantment surcharge");
    it.todo("cursed sword with enchantment 5 stacks both surcharges");
  });

  describe("quote - policy modifiers", () => {
    it.todo("customer with 2 years receives 20% loyalty discount on policy base");
    it.todo("first insurance surcharge applies per item (10% of item base)");
    it.todo("second contract gets 15% follow-up discount on policy base");
  });

  describe("quote - integration examples", () => {
    it.todo("newcomer with cursed steel sword (enchantment 3) yields premium 165 G");
    it.todo("3-year customer's second quote of cursed sword enchantment 7 yields premium 160 G");
    it.todo("cursed sword + plain amulet for newcomer yields 210 G before fee/first-insurance modifiers per spec");
  });

  describe("quote - rounding", () => {
    it.todo("premium that yields fractional amount is rounded up in MHPCO's favor");
  });

  describe("claim - base payouts", () => {
    it.todo("regular steel sword enchantment 3 with 500 G damage yields payout 400 G");
    it.todo("rune with 200 G damage yields payout 100 G");
    it.todo("dragon-material sword enchantment 8 with 1000 G damage yields payout 400 G (50% then deductible)");
    it.todo("dragon-material sword enchantment 5 with 800 G damage yields payout 700 G (full minus deductible)");
    it.todo("steel sword enchantment 9 with 1000 G damage yields payout 400 G (50% then deductible)");
  });

  describe("claim - multiple damages", () => {
    it.todo("dragon attack on sword (500 G) and amulet (300 G) yields payout 600 G (deductible per item)");
    it.todo("two swords in policy, both damaged yields per-item deductible applied");
  });

  describe("claim - rounding", () => {
    it.todo("payout that yields fractional amount is rounded down in MHPCO's favor");
  });

  describe("error handling", () => {
    it.todo("quote with unknown item type throws an error");
    it.todo("claim referencing item not in policy throws an error");
    it.todo("claim with negative damage amount throws an error");
    it.todo("claim with more damages of a type than insured throws an error");
  });
});

