const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

type Item = { type: string };
type Step = { op: string; items: Item[] };
type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const BLOCK_SIZE = 3;
const RUNE_BLOCK_PRICE = 60;

const computeBasePremium = (items: Item[]): number => {
  if (
    items.length === BLOCK_SIZE &&
    items.every((item) => item.type === "rune")
  ) {
    return RUNE_BLOCK_PRICE;
  }
  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
};

const quoteStep = (step: Step): { premium: number } => {
  const base = computeBasePremium(step.items);
  const firstInsurance = base * FIRST_INSURANCE_RATE;
  return { premium: Math.ceil(base + firstInsurance + PROCESSING_FEE) };
};

export const runScenario = (scenario: unknown): unknown => {
  const { steps } = scenario as Scenario;
  return { results: steps.map(quoteStep) };
};

